+            locator.clear();
+            locator.fill(text);
+            log.info("Filled text into element: " + key);
+        } catch (Exception e) {
+            log.error("Failed to fill text into element: " + key, e);
+            throw new AssertionError("Failed to fill text into element: " + key + ". Reason: " + e.getMessage(), e);
+        }
