+			} else if (environment != null && environment.equalsIgnoreCase("dev")){
+				url = ConfigReader.get("devURL");
+				log.info("Using Dev URL: " + url);
+			} else {
+				url = ConfigReader.get("prodURL");
+				log.info("Using Prod URL: " + url);
+			}
+		}
+		log.info("URL: " + url);
+		base = new BaseClass();
+	}
