+
+        // Prefix with random 6 letters
+        for (int i = 0; i < 6; i++) {
+            sb.append(CHARACTERS.charAt(RANDOM.nextInt(CHARACTERS.length())));
+        }
+
+        // Add random number
+        int randomNum = 1000 + RANDOM.nextInt(9000);
+
+        // Combine prefix, number and domain
